sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    // 1. Declare an empty array called 'answer'
    var answer = [];

    // 2. Declare a variable called 'vin', equal to the vin from the path parameter
    var vin = request.pathParams.vin;

    // 3. Perform a GlideRecord query of the x_snc_vehicle_ma_0_vehicle table using the vin
    var vehicleGR = new GlideRecord('x_snc_vehicle_ma_0_vehicle');
    vehicleGR.addQuery('vin', vin);
    vehicleGR.query();

    // 4. Generate an error message and a 404 if no vehicle is found
    if (!vehicleGR.next()) {
        response.setStatus(404);
        response.setBody({
            error: {
                message: 'Vehicle not found',
                detail: 'No vehicle found with VIN: ' + vin
            }
        });
        return;
    }

    // 5. If a vehicle record is found, delete it
    // First, capture the vehicle data before deletion
    var vehicleObj = {
        make: vehicleGR.getValue('make'),
        model: vehicleGR.getValue('model'),
        vin: vehicleGR.getValue('vin'),
        year: vehicleGR.getValue('year'),
        country: vehicleGR.getValue('country'),
        city: vehicleGR.getValue('city'),
        sys_id: vehicleGR.getUniqueValue(),
        message: 'Vehicle deleted.'
    };

    vehicleGR.deleteRecord();

    // 6. If the deletion was successful: set status to 200
    response.setStatus(200);

    // 7. Push this object to the answer variable and include in the response body
    answer.push(vehicleObj);

    response.setBody({
        answer: answer
    });

})(request, response);
